INSERT INTO news (title, slug, body, excerpt, category, status, published_at) VALUES
('إطلاق حملة "شتاء دافئ" لتوزيع الملابس الشتوية', 'shitaa-dafee-2024', '<p>بدأت الجمعية حملتها السنوية لتوزيع الملابس الشتوية والبطانيات على 500 أسرة محتاجة في مختلف مناطق المدينة المنورة. تهدف الحملة إلى توفير الدفء والراحة للأسر المحتاجة خلال فصل الشتاء.</p>', 'بدأت الجمعية حملتها السنوية لتوزيع الملابس الشتوية والبطانيات على 500 أسرة محتاجة', 'events', 'published', '2024-11-05'),
('تخريج 50 متدربًا من برنامج التأهيل المهني', 'takhreej-50-mutadrib', '<p>احتفلت الجمعية بتخريج دفعة جديدة من المتدربين الذين أكملوا برنامج التأهيل المهني بنجاح. تم تدريبهم على مهارات سوق العمل المختلفة وتمكنوا من الحصول على فرص وظيفية مناسبة.</p>', 'احتفلت الجمعية بتخريج دفعة جديدة من المتدربين الذين أكملوا برنامج التأهيل المهني بنجاح', 'achievements', 'published', '2024-10-28'),
('توسيع برنامج كفالة الأسر ليشمل 100 أسرة إضافية', 'tawsee-kafalat-asr', '<p>بفضل دعم المتبرعين الكرام، تمكنت الجمعية من زيادة عدد الأسر المكفولة إلى 600 أسرة. البرنامج يوفر دعم مالي شهري منتظم للأسر المحتاجة لتغطية احتياجاتهم الأساسية.</p>', 'بفضل دعم المتبرعين الكرام، تمكنت الجمعية من زيادة عدد الأسر المكفولة إلى 600 أسرة', 'programs', 'published', '2024-10-20'),
('ماراثون خيري بمشاركة 200 متطوع', 'marathon-khayri-200', '<p>نظمت الجمعية ماراثون خيري ناجح لجمع التبرعات وزيادة الوعي بالقضايا الإنسانية. شارك في الماراثون أكثر من 200 متطوع من مختلف الفئات العمرية.</p>', 'نظمت الجمعية ماراثون خيري ناجح لجمع التبرعات وزيادة الوعي بالقضايا الإنسانية', 'events', 'published', '2024-10-15'),
('توزيع 500 حقيبة مدرسية في بداية العام الدراسي', '500-hageeba-madrasia', '<p>ساهمت الجمعية في تجهيز الطلاب للعام الدراسي الجديد من خلال توزيع الحقائب والأدوات المدرسية على 500 طالب وطالبة من الأسر المحتاجة.</p>', 'ساهمت الجمعية في تجهيز الطلاب للعام الدراسي الجديد من خلال توزيع الحقائب والأدوات المدرسية', 'achievements', 'published', '2024-09-10'),
('إطلاق برنامج جديد للرعاية النفسية', 'raaya-nafsia-jadid', '<p>أضافت الجمعية برنامج دعم نفسي واجتماعي للمستفيدين بالتعاون مع متخصصين في الصحة النفسية. يهدف البرنامج إلى تحسين الحالة النفسية والاجتماعية للمستفيدين.</p>', 'أضافت الجمعية برنامج دعم نفسي واجتماعي للمستفيدين بالتعاون مع متخصصين', 'programs', 'published', '2024-09-01')
INSERT INTO projects (title, slug, short_description, body, status, category, show_on_home, priority) VALUES
('برنامج كفالة الأسر', 'kafalat-al-asr', 'توفير دعم مالي شهري منتظم للأسر المحتاجة لتغطية احتياجاتهم الأساسية من مأكل ومشرب وسكن.', '<p>برنامج شامل لدعم الأسر المحتاجة مادياً ومعنوياً. يوفر البرنامج دعم مالي شهري منتظم يساعد الأسر على تلبية احتياجاتهم الأساسية وتحسين مستوى معيشتهم.</p><p><strong>المستفيدون:</strong> 500 أسرة</p><p><strong>الأهداف:</strong> تحسين مستوى المعيشة للأسر المحتاجة وضمان استقرارهم المالي</p><p><strong>كيفية المساعدة:</strong> التبرع الشهري أو السنوي لكفالة أسرة</p>', 'ongoing', 'اجتماعي', true, 1),
('برنامج الرعاية الصحية', 'raaya-sehhiya', 'تقديم الدعم الصحي والعلاجي للمرضى المحتاجين، وتوفير الأجهزة الطبية والأدوية الضرورية.', '<p>برنامج متكامل للرعاية الصحية يهدف إلى ضمان حصول المرضى المحتاجين على العلاج المناسب دون عوائق مالية.</p><p><strong>المستفيدون:</strong> 800 مستفيد</p><p><strong>الأهداف:</strong> ضمان حصول المرضى على العلاج المناسب دون عوائق مالية</p><p><strong>كيفية المساعدة:</strong> التبرع لصندوق العلاج أو التبرع بأجهزة طبية</p>', 'ongoing', 'صحي', true, 2),
('مشروع التأهيل المهني', 'tahheel-mihni', 'تدريب وتأهيل الشباب على المهارات المطلوبة في سوق العمل لمساعدتهم في الحصول على فرص وظيفية.', '<p>برنامج تدريبي شامل لتأهيل الشباب على المهارات المطلوبة في سوق العمل.</p><p><strong>المستفيدون:</strong> 300 شاب وشابة</p><p><strong>الأهداف:</strong> تمكين الشباب من الاستقلال المالي وتقليل البطالة</p><p><strong>كيفية المساعدة:</strong> دعم برامج التدريب أو توفير فرص توظيف</p>', 'ongoing', 'توظيف', true, 3),
('برنامج الدعم التعليمي', 'daam-taaleemi', 'توفير المستلزمات الدراسية والرسوم الدراسية لأبناء الأسر المحتاجة لضمان استمرارهم في التعليم.', '<p>برنامج شامل لدعم التعليم يضمن حصول جميع الأطفال على فرصة التعليم الجيد.</p><p><strong>المستفيدون:</strong> 600 طالب</p><p><strong>الأهداف:</strong> ضمان حصول جميع الأطفال على فرصة التعليم الجيد</p><p><strong>كيفية المساعدة:</strong> كفالة طالب أو التبرع للحقائب المدرسية</p>', 'ongoing', 'تعليم', false, 4),
('مشروع الإسكان التنموي', 'iskan-tanmawi', 'ترميم وصيانة منازل الأسر المحتاجة لتوفير بيئة سكنية آمنة وصحية.', '<p>مشروع يهدف إلى توفير مسكن لائق وآمن للأسر المستحقة من خلال برامج الترميم والصيانة.</p><p><strong>المستفيدون:</strong> 150 أسرة</p><p><strong>الأهداف:</strong> توفير مسكن لائق وآمن للأسر المستحقة</p><p><strong>كيفية المساعدة:</strong> التبرع لصندوق الإسكان</p>', 'ongoing', 'اجتماعي', false, 5),
('برنامج الأيتام', 'baramij-al-aytam', 'رعاية شاملة للأيتام تشمل الدعم المالي والتعليمي والنفسي لضمان مستقبل أفضل لهم.', '<p>برنامج متكامل لرعاية الأيتام يضمن حقوقهم ويوفر لهم مستقبل أفضل.</p><p><strong>المستفيدون:</strong> 200 يتيم</p><p><strong>الأهداف:</strong> توفير رعاية متكاملة للأيتام وضمان حقوقهم</p><p><strong>كيفية المساعدة:</strong> كفالة يتيم أو دعم البرامج الترفيهية</p>', 'ongoing', 'اجتماعي', false, 6)
