INSERT INTO static_pages (title, slug, type, summary, body, status, show_in_menu, menu_label, menu_order) VALUES
('من نحن', 'about', 'about', 'تعريف بالجمعية وأهدافها ورؤيتها ورسالتها', '<h1>من نحن</h1><p>تأسست جمعية الرعاية الخيرية في عام 2009 بهدف تقديم الدعم والرعاية للأسر المحتاجة في المجتمع السعودي. منذ تأسيسها، نجحت الجمعية في مساعدة آلاف الأسر وتقديم خدمات متنوعة تشمل الدعم المادي، الرعاية الصحية، التعليم، والتأهيل المهني.</p><p>تعمل الجمعية تحت إشراف وزارة الموارد البشرية والتنمية الاجتماعية، وتلتزم بأعلى معايير الشفافية والمساءلة في إدارة مواردها وتنفيذ برامجها.</p>', 'published', true, 'من نحن', 2),
('اتصل بنا', 'contact', 'contact', 'معلومات التواصل مع الجمعية', '<h1>اتصل بنا</h1><p>نحن هنا لمساعدتك. يمكنك التواصل معنا عبر:</p><ul><li>البريد الإلكتروني: info@example.com</li><li>الهاتف: 0500000000</li><li>العنوان: المدينة المنورة، المملكة العربية السعودية</li></ul>', 'published', true, 'اتصل بنا', 10)
